#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int t;    cin >> t;    while(t--) {        ll x, y;        cin >> x >> y;        ll s = x - y;        ll ans;        if (s == 0) {            ans = 1;        } else {            ll n = abs(s);            ans = 0;            for (ll i = 1; i * i <= n; i++) {                if (n % i == 0) {                    if (i * i == n) ans++;                    else ans += 2;                }            }        }        cout << ans << endl;        if (s >= 0) {            while (x--) cout << 1 << " ";            while (y--) cout << -1 << " ";        } else {            while (y--) cout << -1 << " ";            while (x--) cout << 1 << " ";        }        cout << endl;    }    return 0;}